
package com.example.taxgap.domain.dto; import com.example.taxgap.domain.enums.TransactionType; import jakarta.validation.constraints.*; import java.math.BigDecimal;
public class TransactionUploadItem { @NotBlank private String transactionId; @NotBlank private String date; @NotBlank private String customerId; @NotNull @DecimalMin(value="0.01") private BigDecimal amount; @NotNull @DecimalMin(value="0.00") private BigDecimal taxRate; private BigDecimal reportedTax; @NotNull private TransactionType transactionType; private String originalSaleTransactionId;
 public String getTransactionId(){return transactionId;} public void setTransactionId(String v){transactionId=v;} public String getDate(){return date;} public void setDate(String v){date=v;} public String getCustomerId(){return customerId;} public void setCustomerId(String v){customerId=v;} public BigDecimal getAmount(){return amount;} public void setAmount(BigDecimal v){amount=v;} public BigDecimal getTaxRate(){return taxRate;} public void setTaxRate(BigDecimal v){taxRate=v;} public BigDecimal getReportedTax(){return reportedTax;} public void setReportedTax(BigDecimal v){reportedTax=v;} public TransactionType getTransactionType(){return transactionType;} public void setTransactionType(TransactionType v){transactionType=v;} public String getOriginalSaleTransactionId(){return originalSaleTransactionId;} public void setOriginalSaleTransactionId(String v){originalSaleTransactionId=v;} }
